diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
index 5eb807dcb76c..28d016af9601 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSimplifyDemanded.cpp
@@ -997,17 +997,34 @@ Value *InstCombinerImpl::SimplifyDemandedUseBits(Instruction *I,
             uint64_t MaskedGEPIndex = HighBitsGEPIndex | MaskedLowBitsGEPIndex;

             if (MaskedGEPIndex != GEPIndex) {
-              auto *GEP = cast<GetElementPtrInst>(II->getArgOperand(0));
-              Builder.SetInsertPoint(I);
-              Type *GEPIndexType =
-                  DL.getIndexType(GEP->getPointerOperand()->getType());
-              Value *MaskedGEP = Builder.CreateGEP(
-                  GEP->getSourceElementType(), InnerPtr,
-                  ConstantInt::get(GEPIndexType, MaskedGEPIndex),
-                  GEP->getName(), GEP->isInBounds());
-
-              replaceOperand(*I, 0, MaskedGEP);
-              return I;
+            if (MaskedGEPIndex != GEPIndex) {
+              Value *GEPVal = II->getArgOperand(0);
+              if (auto *GEP = dyn_cast<GetElementPtrInst>(GEPVal)) {
+                // Handle GetElementPtrInst case
+                Builder.SetInsertPoint(I);
+                Type *GEPIndexType =
+                    DL.getIndexType(GEP->getPointerOperand()->getType());
+                Value *MaskedGEP = Builder.CreateGEP(
+                    GEP->getSourceElementType(), InnerPtr,
+                    ConstantInt::get(GEPIndexType, MaskedGEPIndex),
+                    GEP->getName(), GEP->isInBounds());
+
+                replaceOperand(*I, 0, MaskedGEP);
+                return I;
+              } else if (auto *CE = dyn_cast<ConstantExpr>(GEPVal)) {
+                // Handle ConstantExpr GEP case
+                if (CE->getOpcode() == Instruction::GetElementPtr) {
+                  Builder.SetInsertPoint(I);
+                  Type *GEPIndexType = DL.getIndexType(CE->getOperand(0)->getType());
+                  Value *MaskedGEP = Builder.CreateGEP(
+                      CE->getOperand(0)->getType()->getPointerElementType(), InnerPtr,
+                      ConstantInt::get(GEPIndexType, MaskedGEPIndex),
+                      "", CE->isInBounds());
+                  replaceOperand(*I, 0, MaskedGEP);
+                  return I;
+                }
+              }
+            }
             }
           }
         }
